-- W1.6 questions batch 6147/9310 (10)

INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('judicial-ae9cc487-moex-00074', 'judicial-ae9cc487', 'judicial-ae9cc487-moex-111-de0a21a2', 'sub-judicial-ae9cc487-01', NULL, 'essay', '甲涉犯毒品危害防制條例罪嫌，經檢察官依法提起公訴，辯護人乙於審
判中主張證人丙在偵查中向檢察官所為之證述，並無結文附卷，顯未經
具結，自無證據能力，檢察官遂聲請證人丙至法庭作證，丙於法庭上證
稱：「其於偵查中曾簽具結文」云云，審判終結，法院以前述證據形成心
證，諭知甲有罪。辯護人不服，以「檢察官之訊問筆錄雖記載『諭知具
結之義務及偽證之處罰，並命證人朗讀結文後具結』等語，然無結文附
卷可稽，因不符法定具結程序採書面結文之形式要件，應不發生具結之
效力，其證言無證據能力。」提起上訴。試論辯護人之主張是否有理由？
（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:59+00:00", "source_pdf_sha1": "989768362d17", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "110", "s": "0501", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法與刑事訴訟法", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-電子資訊組"}'::jsonb, NULL),
  ('judicial-ae9cc487-moex-00075', 'judicial-ae9cc487', 'judicial-ae9cc487-moex-111-de0a21a2', 'sub-judicial-ae9cc487-01', NULL, 'essay', '被告甲涉犯刑法酒駕致人於死罪嫌，經檢察官依法提起公訴，審判中，
被告甲及其辯護人乙，對於證人丙於審判外之陳述，均明示同意作為證
據，復經提示上開供述證據時，亦併就證據能力表示沒有意見。法院審
酌上開證據作成時之情況，認無不適當之情形，復敘明符合證據適當性
之理由，乃依法踐行調查程序，認定被告甲有罪。甲依法提起上訴，經
上訴審撤銷原審判決，發回更審。試論被告甲及辯護人乙得否於更審第
一次審判期日時，撤回同意證人丙之傳聞證據之證據能力？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:59+00:00", "source_pdf_sha1": "989768362d17", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "110", "s": "0501", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法與刑事訴訟法", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-電子資訊組"}'::jsonb, NULL),
  ('judicial-ae9cc487-moex-00076', 'judicial-ae9cc487', 'judicial-ae9cc487-moex-111-359207d9', 'sub-judicial-ae9cc487-07', NULL, 'single_choice', '黃先生回到母校，看見校長室牆上掛滿匾額，下列那一個題辭不適合出現？', '["時雨春風", "澤被三臺", "絃歌盈耳", "功著杏林"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:59+00:00", "source_pdf_sha1": "6d205a249f8d", "answer_pdf_sha1": "40189eca7d37", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "110", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文、公文與測驗)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-電子資訊組"}'::jsonb, NULL),
  ('judicial-ae9cc487-moex-00077', 'judicial-ae9cc487', 'judicial-ae9cc487-moex-111-359207d9', 'sub-judicial-ae9cc487-07', NULL, 'single_choice', '「愛，是人類生命存在的心靈經驗之一，只有真切地面對自己以及所愛之人內在活生 生的心靈，才能照見彼此不能相愛的障礙而加以克服。然而，他們卻遺忘了自己的 存在，只是不斷地追逐著各種外在的知識，以為這樣就能幸福快樂。」 下列敘述何者最貼近本文的旨趣？', '["知識的追逐讓人們忘了如何相愛", "體認自身之存在為追逐知識之本", "人經常忘記照見自己而產生了相愛的障礙", "相愛的根本在於面對彼此的內心而非知識"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:59+00:00", "source_pdf_sha1": "6d205a249f8d", "answer_pdf_sha1": "40189eca7d37", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "110", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文、公文與測驗)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-電子資訊組"}'::jsonb, NULL),
  ('judicial-ae9cc487-moex-00078', 'judicial-ae9cc487', 'judicial-ae9cc487-moex-111-359207d9', 'sub-judicial-ae9cc487-07', NULL, 'single_choice', '「美是一種生命整體存在感的湧現。當此際必然是物我兩忘，情景交融，渾成一片， 而容不下絲毫的分辨與思維。當天邊飛過一抹彩霞，你只合目瞪口呆；連一句『好 美啊』的呢喃，都已是心靈對此境的意識與抽離，也早已構成對美的留戀與破壞。」 根據上文，最符合美的感受是：', '["盡在不言中", "物我保持距離", "感官與意識的交融", "生命主體的思維湧現"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:59+00:00", "source_pdf_sha1": "6d205a249f8d", "answer_pdf_sha1": "40189eca7d37", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "110", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文、公文與測驗)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-電子資訊組"}'::jsonb, NULL),
  ('judicial-ae9cc487-moex-00079', 'judicial-ae9cc487', 'judicial-ae9cc487-moex-111-359207d9', 'sub-judicial-ae9cc487-07', NULL, 'single_choice', '「大多數的商業圖表都是披薩，餡料不多以免消化不良，它能在短時間內提供資訊， 用不著太多文字說明。客戶資料蒐集差不多了，就畫個條狀圖。計畫又訂出新的期 限，就畫個時程圖。但有些會議需要很多說明，例如剛併購一家公司，要向高層主 管解說營運策略如何調整，這時，披薩無法滿足胃口，要端出全套酒席，展示精細 的圖表。這種圖表能醞釀創意，引發大家交換意見，進而解決問題。」 下列敘述，最符合上文觀點的是：', '["披薩式圖表適用於基層會議，酒席式圖表適用於主管會議", "披薩式圖表適用於宣達要點，酒席式圖表適用於探討細節", "披薩式與酒席式圖表雖然各有功能，但皆應儘量少用文字", "披薩式與酒席式圖表雖然繁簡不一，但皆為引發充分討論"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:59+00:00", "source_pdf_sha1": "6d205a249f8d", "answer_pdf_sha1": "40189eca7d37", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "110", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文、公文與測驗)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-電子資訊組"}'::jsonb, NULL),
  ('judicial-ae9cc487-moex-00080', 'judicial-ae9cc487', 'judicial-ae9cc487-moex-111-359207d9', 'sub-judicial-ae9cc487-07', NULL, 'single_choice', '「有一座龐大的旅館，設備陳舊，管理鬆懈，營業額一落千丈。旅館的所有人聘請一 位專家來從事革新和整頓。三個月後，專家對旅館的現況有了透徹的了解，提出一 份詳細的計畫，主張把房子拆掉重新建造大樓，現有工作人員一律遣散，重新招考 訓練。旅館所有人無法接受這樣的計畫，聘請另一位專家來擔任經理。這位專家在 視察旅館的業務之後，下令換裝所有房間的自來水龍頭。新的龍頭，式樣美觀，操 作方便，絕不漏水，旅客在半夜再也聽不到滴漏之聲，可以安享一夜好睡了。就這 樣，新任經理從小處著手，積小為大，終於使旅館的作風煥然一新。旅客們發現， 這家旅館的房子雖然陳舊，但是堅固；式樣雖然古老，但是引人。於是近者悅，遠 者來。」 根據上文，旅館終能近悅遠來，其主要關鍵在於管理者：', '["不愛虛名，惟儉是尚", "前事不忘，後事之師", "圖難於其易，為大於其細", "毀譽無動於衷，榮辱在所不計"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:59+00:00", "source_pdf_sha1": "6d205a249f8d", "answer_pdf_sha1": "40189eca7d37", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "110", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文、公文與測驗)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-電子資訊組"}'::jsonb, NULL),
  ('judicial-ae9cc487-moex-00081', 'judicial-ae9cc487', 'judicial-ae9cc487-moex-111-359207d9', 'sub-judicial-ae9cc487-07', NULL, 'single_choice', '「有些公司誤以為科技能取代人力經驗所累積的技能與判斷力。資深的航太工程師 因公司進行人事精簡，在勸退聲中離開崗位。但公司為了延續重要工作，又得重新 僱用這些離職的工程師。有些看似『可有可無』的中階主管去職後，公司才了解到 他們所經手的是關鍵性工作的相關知識，公司所損失的絕非那幾個正式職稱而已。」 下列選項，最符合上文旨意的是：', '["科技能創造知識價值卻無法取代勞力工作", "公司核心知識不宜因人事更迭而中斷傳承", "精簡人事成本必造成公司動盪缺乏向心力", "公司的人事規劃不可忽略中階主管的重要"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:59+00:00", "source_pdf_sha1": "6d205a249f8d", "answer_pdf_sha1": "40189eca7d37", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "110", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文、公文與測驗)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-電子資訊組"}'::jsonb, NULL),
  ('judicial-ae9cc487-moex-00082', 'judicial-ae9cc487', 'judicial-ae9cc487-moex-111-359207d9', 'sub-judicial-ae9cc487-07', NULL, 'single_choice', '「杜克大學的麥克•沙舍夫斯基是非常成功的大學籃球隊教練，他對這種評論曾有明 智的評語。有位廣播節目評論員批評他在某場比賽的戰術指導，《華爾街日報》的記 者問他對此有何反應，他回答：『大家都可以發表意見，但不是每個人都具備形成有 價值意見所須掌握的資訊。我寧可聽我信任的人的意見，不聽脫口秀節目或報導。』」 上文中的「這種評論」是指：', '["缺乏專業的評論", "球壇權威的評論", "報紙刊載的評論", "吝於讚美的評論"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:59+00:00", "source_pdf_sha1": "6d205a249f8d", "answer_pdf_sha1": "40189eca7d37", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "110", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文、公文與測驗)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-電子資訊組"}'::jsonb, NULL),
  ('judicial-ae9cc487-moex-00083', 'judicial-ae9cc487', 'judicial-ae9cc487-moex-111-359207d9', 'sub-judicial-ae9cc487-07', NULL, 'single_choice', '「很久以前，人類都還光著腳走路。一位國王到某個偏遠的鄉間旅遊，由於路面崎嶇 不平，有很多碎石頭，刺得他的腳板又痛又麻。回到王宮後，他下令要將國內所有 道路都鋪上一層牛皮。這樣做，不只是為自己，還可造福他的人民，讓大家走路時 不再受刺痛之苦。但即使殺光國內所有的牛，也湊不到足夠的皮革，而所花費的金 錢、動用的人力，更不知有多少。這個辦法很愚蠢而且根本做不到，但因為是國王 的命令，大家也只能搖頭嘆息。一位聰明的僕人大膽向國王提出建言：『國王啊！為 什麼您要勞師動眾，犧牲那麼多頭牛，花費那麼多金錢呢？您何不只用兩小片牛皮 包住您的腳呢？』國王聽了很驚訝，當下領悟，於是立刻收回成命，改採這個建議。 據說，這就是『皮鞋』的由來。」 上文故事寓意，與下列何者最為相近？', '["這個世界只有想不到的，沒有做不到的", "想改變世界，很難；要改變自己，則較為容易", "得到一件東西需要智慧，放棄一樣東西則需要勇氣", "當命運交給你一顆酸檸檬，你要想辦法把它做成一杯可口的檸檬汁"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:59+00:00", "source_pdf_sha1": "6d205a249f8d", "answer_pdf_sha1": "40189eca7d37", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "110", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文、公文與測驗)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-電子資訊組"}'::jsonb, NULL)
